// Parse Interac payment details from Gmail and Yahoo emails
const payments = [];

for (const item of $input.all()) {
  try {
    // Récupérer le contenu de l'email (texte ou HTML)
    const emailBody = item.json.text || item.json.textPlain || item.json.snippet || '';
    const emailHtml = item.json.html || item.json.textAsHtml || '';
    const emailSubject = item.json.subject || '';
    const emailDate = item.json.date || item.json.receivedDateTime || new Date().toISOString();

    // Déterminer la source
    const emailSource = item.json.labelIds ? 'Gmail' : 'Yahoo';

    // Combine text and HTML for better parsing
    const fullContent = emailBody + ' ' + emailHtml;

    // === EXTRACTION DU MONTANT ===
    let amount = null;

    // Pattern 1: "requested $XXX.XX from you" (Interac request)
    let amountMatch = fullContent.match(/requested\s+\$([0-9,]+\.?[0-9]{0,2})\s+from\s+you/i);

    // Pattern 2: "Transfer Amount XXX.XX CAD" (Western Union)
    if (!amountMatch) {
      amountMatch = fullContent.match(/Transfer\s+Amount\s+([0-9,]+\.?[0-9]{0,2})\s+CAD/i);
    }

    // Pattern 3: Generic "$XXX.XX (CAD)" or "$XXX.XX CAD"
    if (!amountMatch) {
      amountMatch = fullContent.match(/\$([0-9,]+\.?[0-9]{0,2})\s*\(CAD\)/i);
    }

    // Pattern 4: Generic "CAD XXX.XX" or "$XXX.XX"
    if (!amountMatch) {
      amountMatch = fullContent.match(/(?:CAD|\$)\s*([0-9,]+\.?[0-9]{0,2})/i);
    }

    if (amountMatch) {
      amount = parseFloat(amountMatch[1].replace(/,/g, ''));
    }

    // === EXTRACTION DU NOM DU LOCATAIRE ===
    let tenantName = '';

    // Pattern 1: From subject "SENDER_NAME has requested"
    let nameMatch = emailSubject.match(/^Interac\s+e-Transfer:\s+([A-Z\s]+)\s+has\s+requested/i);

    // Pattern 2: From "Receiver Details" section (Western Union)
    if (!nameMatch) {
      nameMatch = fullContent.match(/Receiver\s+Details[^N]+Name\s+([A-Za-z\s-]+?)(?:\s+Payout|<)/i);
    }

    // Pattern 3: From "Hi [NAME]" or "Sent From: [NAME]"
    if (!nameMatch) {
      nameMatch = fullContent.match(/(?:Hi|Sent\s+From:)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)/);
    }

    // Pattern 4: From email sender field
    if (!nameMatch) {
      const fromField = item.json.from?.value?.[0]?.name || item.json.from?.text || '';
      if (fromField && !fromField.includes('Union') && !fromField.includes('Interac') && !fromField.includes('notify')) {
        tenantName = fromField.replace(/[<>"]/g, '').trim();
      }
    }

    if (nameMatch) {
      tenantName = nameMatch[1].trim();
    }

    // === EXTRACTION DE L'EMAIL DU LOCATAIRE ===
    let tenantEmail = '';

    // From reply-to field
    if (item.json.replyTo?.value?.[0]?.address) {
      tenantEmail = item.json.replyTo.value[0].address;
    }

    // Fallback to from field if reply-to doesn't exist
    if (!tenantEmail && item.json.from?.value?.[0]?.address) {
      const fromAddr = item.json.from.value[0].address;
      // Avoid system emails
      if (!fromAddr.includes('notify@') && !fromAddr.includes('noreply@')) {
        tenantEmail = fromAddr;
      }
    }

    // === PARSE DATE ===
    const paymentDate = new Date(emailDate).toISOString().split('T')[0];

    // === DÉTECTION DU TYPE DE TRANSACTION ===
    let transactionType = 'Unknown';
    if (emailSubject.includes('has requested')) {
      transactionType = 'Interac Request';
    } else if (emailSubject.includes('ready for pickup') || fullContent.includes('Western Union')) {
      transactionType = 'Western Union Transfer';
    } else if (emailSubject.includes('Interac e-Transfer')) {
      transactionType = 'Interac Transfer';
    }

    // === EXTRACTION DU MTCN (Western Union) ===
    let mtcn = '';
    const mtcnMatch = fullContent.match(/MTCN[:\s]+(\d{10})/i);
    if (mtcnMatch) {
      mtcn = mtcnMatch[1];
    }

    // Only add if we have at least amount and name
    if (amount && tenantName) {
      payments.push({
        json: {
          tenantName: tenantName,
          tenantEmail: tenantEmail,
          amount: amount,
          date: paymentDate,
          source: emailSource,
          transactionType: transactionType,
          mtcn: mtcn || 'N/A',
          subject: emailSubject,
          rawSnippet: emailBody.substring(0, 150) // Keep first 150 chars for reference
        }
      });
    } else {
      console.log(`Skipped email - Amount: ${amount}, Name: ${tenantName}`);
    }

  } catch (error) {
    console.log('Error parsing email:', error.message, error.stack);
  }
}

console.log(`Successfully parsed ${payments.length} payments`);
return payments;

// Aggregate payments by tenant email
// Sum all payments from the same customer (handles multiple payments per month)
// Include current month name

const aggregatedPayments = {};

// Get current month name
const currentDate = new Date();
const monthNames = ['January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'];
const currentMonth = monthNames[currentDate.getMonth()];

// Group payments by email
for (const payment of $input.all()) {
  const email = payment.json.tenantEmail?.toLowerCase().trim();
  if (!email) continue;

  if (!aggregatedPayments[email]) {
    aggregatedPayments[email] = {
      tenantEmail: email,
      tenantName: payment.json.tenantName,
      totalAmount: 0,
      lastPaymentDate: payment.json.date,
      transactionType: payment.json.transactionType,
      paymentCount: 0,
      allDates: [],
      month: currentMonth
    };
  }

  // Add to total
  aggregatedPayments[email].totalAmount += parseFloat(payment.json.amount) || 0;
  aggregatedPayments[email].paymentCount += 1;
  aggregatedPayments[email].allDates.push(payment.json.date);

  // Keep the latest date
  if (payment.json.date > aggregatedPayments[email].lastPaymentDate) {
    aggregatedPayments[email].lastPaymentDate = payment.json.date;
  }
}

// Convert to array format for n8n
const result = Object.values(aggregatedPayments).map(agg => ({
  json: {
    tenantEmail: agg.tenantEmail,
    tenantName: agg.tenantName,
    amount: agg.totalAmount,
    date: agg.lastPaymentDate,
    month: agg.month,
    transactionType: agg.transactionType,
    paymentCount: agg.paymentCount,
    allPaymentDates: agg.allDates.join(', ')
  }
}));

console.log(`Aggregated ${Object.keys(aggregatedPayments).length} unique tenants with ${$input.all().length} total payments for ${currentMonth}`);
return result;

// Identify tenants with payment issues
// Check for: No payment OR Partial payment (less than Rent amount)
// Filter: Skip invalid entries (no rent amount, duplicate emails, etc.)

const allTenants = $('Read Tenant List').all();
const unpaidTenants = [];
const seenEmails = new Set(); // Track seen emails to avoid duplicates

for (const tenant of allTenants) {
  const tenantData = tenant.json;

  // Skip if no email
  if (!tenantData.Email || tenantData.Email.trim() === '') {
    continue;
  }

  // Skip if no rent amount defined (invalid tenant)
  const rentAmount = parseFloat(tenantData['Rent amount']) || 0;
  if (rentAmount === 0) {
    console.log(`Skipped tenant ${tenantData.Name} - no rent amount defined`);
    continue;
  }

  const tenantEmail = tenantData.Email.toLowerCase().trim();

  // Skip if we already processed this email (avoid duplicates)
  if (seenEmails.has(tenantEmail)) {
    console.log(`Skipped duplicate email: ${tenantEmail}`);
    continue;
  }
  seenEmails.add(tenantEmail);

  const tenantName = tenantData.Name || 'Unknown';
  const payment = parseFloat(tenantData.Payment) || 0;

  // Check if:
  // 1. No payment at all (payment = 0)
  // 2. Partial payment (payment < rent amount)
  if (payment === 0) {
    unpaidTenants.push({
      json: {
        name: tenantName,
        email: tenantEmail,
        rentAmount: rentAmount,
        amountPaid: 0,
        amountDue: rentAmount,
        lastPaymentDate: tenantData['Last payment'] || 'Never',
        status: 'UNPAID',
        paymentStatus: 'NO_PAYMENT'
      }
    });
  } else if (payment < rentAmount) {
    unpaidTenants.push({
      json: {
        name: tenantName,
        email: tenantEmail,
        rentAmount: rentAmount,
        amountPaid: payment,
        amountDue: rentAmount - payment,
        lastPaymentDate: tenantData['Last payment'] || 'Never',
        status: 'PARTIAL_PAYMENT',
        paymentStatus: 'PARTIAL'
      }
    });
  }
}

console.log(`Found ${unpaidTenants.length} tenants with payment issues (unpaid or partial)`);
return unpaidTenants;

// Prepare personalized reminder emails based on payment status

const reminderEmails = [];

for (const unpaidTenant of $input.all()) {
  const tenant = unpaidTenant.json;

  if (!tenant.email) {
    continue;
  }

  let emailBody = '';
  let subject = '';

  if (tenant.paymentStatus === 'NO_PAYMENT') {
    // No payment at all
    subject = `Rent Payment Due - $${tenant.rentAmount}`;
    emailBody = `Hello ${tenant.name},\n\nThis is a friendly reminder that your rent payment of $${tenant.rentAmount} for this month is due.\n\nPlease send your payment as soon as possible via Interac e-Transfer.\n\nThank you,\nProperty Management`;
  } else if (tenant.paymentStatus === 'PARTIAL') {
    // Partial payment
    subject = `Outstanding Rent Balance - $${tenant.amountDue}`;
    emailBody = `Hello ${tenant.name},\n\nWe have received your payment of $${tenant.amountPaid}. However, there is still an outstanding balance of $${tenant.amountDue} remaining for the full rent of $${tenant.rentAmount}.\n\nPlease send the remaining balance via Interac e-Transfer.\n\nThank you,\nProperty Management`;
  }

  reminderEmails.push({
    json: {
      email: tenant.email,
      name: tenant.name,
      rentAmount: tenant.rentAmount,
      amountPaid: tenant.amountPaid,
      amountDue: tenant.amountDue,
      lastPaymentDate: tenant.lastPaymentDate,
      subject: subject,
      body: emailBody,
      status: tenant.paymentStatus
    }
  });
}

console.log(`Prepared ${reminderEmails.length} reminder emails (${reminderEmails.filter(e => e.json.status === 'NO_PAYMENT').length} unpaid, ${reminderEmails.filter(e => e.json.status === 'PARTIAL').length} partial)`);
return reminderEmails;
